import * as React from 'react';
import useAsyncFn from './useAsyncFn';
import type { FunctionReturningPromise } from './types';
export type { AsyncState, AsyncFnReturn } from './useAsyncFn';

export default function useAsync<T extends FunctionReturningPromise>(fn: T) {
  const [state, callback] = useAsyncFn(fn, {
    initialState: {
      loading: true,
    },
  });

  React.useEffect(() => {
    callback();
  }, [callback]);

  return state;
}
